     1→import { Injectable, UseInterceptors } from '@nestjs/common';
     2→import { BaseQueueService } from '../shared/base-queue.service';
     3→import { RedisConnectionService } from '../shared/redis-connection.service';
     4→import { LoggingStorage } from '@app/logging';
     5→import { AuditingInterceptor, AuditingService } from '@app/auditing';
     6→import { EnrichmentPipeline } from './enrichment-pipeline.service';
     7→import { TextExtractionJobData, PipelineJobResult } from './text-extraction.interface';
     8→
     9→export { PipelineJobResult };
    10→
    11→/**
    12→ * BullMQ queue service for the text-enrichment pipeline.
    13→ *
    14→ * Delegates all extraction logic to {@link EnrichmentPipeline}, which in turn
    15→ * delegates to every registered {@link ITextEnrichment} via the
    16→ * {@link TextEnrichmentManager}.
    17→ *
    18→ * This service is responsible only for:
    19→ *  - Queue / worker lifecycle (inherited from {@link BaseQueueService})
    20→ *  - Enqueuing jobs with auditing milestones
    21→ *  - Exposing fire-and-forget (`addTextExtractionJob`) and
    22→ *    wait-for-result (`processTextExtractionJobAndWait`) APIs
    23→ */
    24→@Injectable()
    25→@UseInterceptors(AuditingInterceptor)
    26→export class TextExtractionQueueService extends BaseQueueService<
    27→    TextExtractionJobData,
    28→    PipelineJobResult
    29→> {
    30→    // -----------------------------------------------------------------------
    31→    // Abstract property implementations required by BaseQueueService
    32→    // -----------------------------------------------------------------------
    33→    protected readonly queueName = 'text-extraction-dedicated';
    34→    protected readonly jobName = 'process-text-extraction';
    35→    protected readonly defaultRedisDb = '6';
    36→
    37→    constructor(
    38→        redisConnection: RedisConnectionService,
    39→        loggingStorage: LoggingStorage,
    40→        private readonly enrichmentPipeline: EnrichmentPipeline,
    41→        private readonly auditingService: AuditingService,
    42→    ) {
    43→        super(redisConnection, loggingStorage);
    44→    }
    45→
    46→    protected getRedisDbEnvVar(): string | undefined {
    47→        return process.env.REDIS_TEXT_EXTRACTION_DB;
    48→    }
    49→
    50→    /** Pure delegation to the pipeline — queue service only handles infrastructure */
    51→    protected async processJob(data: TextExtractionJobData): Promise<PipelineJobResult> {
    52→        return this.enrichmentPipeline.processJob(data.documentSourceId);
    53→    }
    54→
    55→    // -----------------------------------------------------------------------
    56→    // Public API
    57→    // -----------------------------------------------------------------------
    58→
    59→    /**
    60→     * Enqueue a text extraction job and return the job ID immediately without
    61→     * waiting for completion.
    62→     */
    63→    async addTextExtractionJob(
    64→        documentSourceId: string,
    65→        neo4jCredentials?: Record<string, unknown>,
    66→        transactionId?: string,
    67→        isRetry?: boolean,
    68→        requestData?: Record<string, unknown>,
    69→    ): Promise<string> {
    70→        this.logger.verbose(`Adding text extraction job for document ${documentSourceId}`);
    71→
    72→        const milestoneId = await this.auditingService.createMilestone(
    73→            'enrichment-text-extraction',
    74→            {
    75→                documentSourceId,
    76→                isRetry,
    77→                methodName: 'addTextExtractionJob',
    78→                className: 'TextExtractionQueueService',
    79→            },
    80→        );
    81→
    82→        try {
    83→            const jobData: TextExtractionJobData = {
    84→                documentSourceId,
    85→                neo4jCredentials,
    86→                transactionId,
    87→                isRetry,
    88→                requestData,
    89→            };
    90→
    91→            const jobId = await this.createJob(jobData);
    92→
    93→            await this.auditingService.complete(milestoneId, {
    94→                success: true,
    95→                jobId,
    96→                documentSourceId,
    97→            });
    98→
    99→            return jobId;
   100→        } catch (error) {
   101→            await this.auditingService.fail(milestoneId, error);
   102→            throw error;
   103→        }
   104→    }
   105→
   106→    /**
   107→     * Enqueue a text extraction job and wait for it to finish, returning the
   108→     * full {@link PipelineJobResult}.
   109→     */
   110→    async processTextExtractionJobAndWait(
   111→        documentSourceId: string,
   112→        neo4jCredentials?: Record<string, unknown>,
   113→        transactionId?: string,
   114→        isRetry?: boolean,
   115→        requestData?: Record<string, unknown>,
   116→    ): Promise<PipelineJobResult> {
   117→        this.logger.log(`🚀 Starting text extraction pipeline for document: ${documentSourceId}`);
   118→
   119→        const jobId = await this.addTextExtractionJob(
   120→            documentSourceId,
   121→            neo4jCredentials,
   122→            transactionId,
   123→            isRetry,
   124→            requestData,
   125→        );
   126→
   127→        return this.waitForJobCompletion(jobId);
   128→    }
   129→
   130→    // All other queue utility methods (getQueueStatus, getJobDetails, cancelJob, etc.)
   131→    // are inherited from BaseQueueService.
   132→}
