     1→import { Injectable, Logger } from '@nestjs/common';
     2→import { randomUUID } from 'crypto';
     3→import { TemporalRepository, TemporalEntityData } from '@app/discovery-neo/temporal/temporal.repository';
     4→import { ITextEnrichment, TextChunk, EnrichmentContext, EnrichmentResult } from '../text-enrichment.interface';
     5→import { TemporalExtractor } from './temporal.extractor';
     6→import { TemporalEntityType } from './temporal.types';
     7→
     8→/** Typed result specific to the temporal enrichment. */
     9→export interface TemporalEnrichmentResult extends EnrichmentResult {
    10→    enrichmentName: 'temporal';
    11→    /** Count per entity type (date, time, datetime, duration, frequency) */
    12→    entitiesByType: Partial<Record<TemporalEntityType, number>>;
    13→}
    14→
    15→/**
    16→ * Text enrichment definition for temporal entity extraction.
    17→ *
    18→ * Implements {@link ITextEnrichment} and is registered with the
    19→ * {@link TextEnrichmentManager} at module initialisation time.
    20→ *
    21→ * Responsibilities:
    22→ *  1. Iterate the supplied chunks and delegate to the pure stateless
    23→ *     {@link TemporalExtractor} (chrono-node) for date/time/duration/frequency parsing.
    24→ *  2. Persist all identified entities to Neo4j via {@link TemporalRepository}.
    25→ *  3. Return a typed {@link TemporalEnrichmentResult} for pipeline aggregation.
    26→ *
    27→ * This class intentionally has no knowledge of Postgres — chunk fetching is
    28→ * handled upstream by {@link EnrichmentPipeline}.
    29→ */
    30→@Injectable()
    31→export class TemporalEnrichment implements ITextEnrichment<TemporalEnrichmentResult> {
    32→    readonly name = 'temporal' as const;
    33→    readonly description = 'Extracts temporal entities (dates, times, durations, frequencies) using chrono-node';
    34→
